+func newTransactionalReload(storagePath string) *transactionalReload {
+	t := &transactionalReload{stateFile: filepath.Join(storagePath, "reload-status.json")}
+	t.outcome = reloadOutcome{ErrorCategory: "none", AppliedReloaders: []string{}, ReloaderTimingsMS: map[string]int64{}}
+	b, err := os.ReadFile(t.stateFile)
+	if err == nil {
+		var outcome reloadOutcome
+		if json.Unmarshal(b, &outcome) == nil && outcome.ErrorCategory != "" {
+			if outcome.AppliedReloaders == nil {
+				outcome.AppliedReloaders = []string{}
+			}
+			if outcome.ReloaderTimingsMS == nil {
+				outcome.ReloaderTimingsMS = map[string]int64{}
+			}
+			t.outcome = outcome
+		}
+	}
+	return t
+}
+
+func (t *transactionalReload) status() web.ReloadStatus {
+	t.mu.RLock()
+	defer t.mu.RUnlock()
+	o := t.outcome
+	o.AppliedReloaders = append([]string(nil), o.AppliedReloaders...)
+	o.ReloaderTimingsMS = maps.Clone(o.ReloaderTimingsMS)
+	return web.ReloadStatus(o)
+}
+
+func (t *transactionalReload) setLastGood(conf *config.Config) {
+	t.mu.Lock()
+	defer t.mu.Unlock()
+	t.lastGood = conf
+}
+
+func (t *transactionalReload) record(outcome reloadOutcome, logger *slog.Logger) {
+	t.mu.Lock()
+	t.outcome = outcome
+	b, err := json.Marshal(outcome)
+	if err == nil {
+		err = os.WriteFile(t.stateFile, b, 0o644)
+	}
+	t.mu.Unlock()
+	if err != nil {
+		logger.Error("Failed to persist transactional reload outcome", "err", err)
+	}
+}
