+func reloadConfigTransactional(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), transaction *transactionalReload, rls ...reloader) (err error) {
+	outcome := reloadOutcome{
+		LastReloadID:      time.Now().UTC().Format(time.RFC3339Nano),
+		ErrorCategory:     "none",
+		AppliedReloaders:  []string{},
+		ReloaderTimingsMS: map[string]int64{},
+	}
+	defer func() {
+		outcome.LastReloadSuccessful = err == nil
+		transaction.record(outcome, logger)
+		if err == nil {
+			configSuccess.Set(1)
+			configSuccessTime.SetToCurrentTime()
+			callback(true)
+		} else {
+			configSuccess.Set(0)
+			callback(false)
+		}
+	}()
+
+	conf, err := config.LoadFile(filename, agentMode, logger)
+	if err != nil {
+		outcome.ErrorCategory = "load_error"
+		outcome.ErrorMessage = err.Error()
+		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
+	}
+	if enableExemplarStorage && conf.StorageConfig.ExemplarsConfig == nil {
+		conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
+	}
+
+	for _, rl := range rls {
+		started := time.Now()
+		applyErr := rl.reloader(conf)
+		outcome.ReloaderTimingsMS[rl.name] = durationToInt64Millis(time.Since(started))
+		if applyErr == nil {
+			outcome.AppliedReloaders = append(outcome.AppliedReloaders, rl.name)
+			continue
+		}
+
+		outcome.ErrorCategory = "apply_error"
+		outcome.ErrorMessage = applyErr.Error()
+		outcome.FailedReloader = rl.name
+		if len(outcome.AppliedReloaders) == 0 {
+			return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, applyErr)
+		}
+
+		transaction.mu.RLock()
+		lastGood := transaction.lastGood
+		transaction.mu.RUnlock()
+		if lastGood == nil {
+			return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, applyErr)
+		}
+		outcome.RollbackAttempted = true
+		rollbackErr := error(nil)
+		for _, rollback := range rls {
+			started := time.Now()
+			e := rollback.reloader(lastGood)
+			outcome.ReloaderTimingsMS["rollback_"+rollback.name] = durationToInt64Millis(time.Since(started))
+			if e != nil && rollbackErr == nil {
+				rollbackErr = fmt.Errorf("failed to roll back reloader %q: %w", rollback.name, e)
+				outcome.FailedReloader = rollback.name
+			}
+		}
+		outcome.RollbackSuccessful = rollbackErr == nil
+		if rollbackErr != nil {
+			outcome.ErrorCategory = "rollback_error"
+			outcome.ErrorMessage = fmt.Sprintf("apply failed: %v; rollback failed: %v", applyErr, rollbackErr)
+			return rollbackErr
+		}
+		return fmt.Errorf("failed to apply configuration with reloader %q: %w", rl.name, applyErr)
+	}
+
+	transaction.setLastGood(conf)
+	updateGoGC(conf, logger)
+	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
+	return nil
+}
